,p_process_name=>'Set Dark Mode Pref'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    l_dark_mode CHAR(1);',
'BEGIN',
'    SELECT dark_mode',
'    INTO   l_dark_mode',
'    FROM   app_users',
'    WHERE  UPPER(username) = UPPER(V(''APP_USER''));',
'',
'    :P0_DARK_MODE := l_dark_mode;',
'',
'    apex_theme.set_session_style(',
'        p_theme_number => 42,',
'        p_name => CASE l_dark_mode ',
'                      WHEN ''Y'' THEN ''Dankbaarheid Donker'' ',
'                      ELSE ''Dankbaarheid Licht'' ',
'                  END',
'    );',
'EXCEPTION',
'    WHEN NO_DATA_FOUND THEN',
'        :P0_DARK_MODE := ''N'';',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_version_scn=>45399029336017
);
end;
