'        IF v_is_dup = 1 THEN',
'            :P10_DUP_ERROR := ''Je gaf dit antwoord al op ''',
'                || TO_CHAR(v_dup_dt, ''DD Month YYYY'', ''NLS_DATE_LANGUAGE=DUTCH'')',
'                || '' ('' || v_dup_pct || ''% gelijk)'';',
'            :P10_DUP_PREV_TEXT := v_dup_txt;',
'        ELSE',
'            :P10_DUP_ERROR := NULL;',
'            :P10_DUP_PREV_TEXT := NULL;',
'        END IF;',
'    END;'))
